INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ogada, caduca a autorização do pagamento em prestações, e aos montantes em dívida acrescem juros de mora calculados como se o benefício previsto no n.º 1 não tivesse sido concedido, à taxa prevista no n.º 1 do artigo 33.º do Regulamento das Custas Processuais. 
