INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('a o desenvolvimento da sua atividade, mantêm-se mesmo que, findo o processo, venha a ser declarada, no prazo de dois anos, a insolvência do devedor, ou venha a ser por este iniciado um novo processo de reestruturação.
  7 - ....
